const express = require('express');
const multer = require('multer');
const libxmljs = require('libxmljs');

const app = express();
const upload = multer({ 
  storage: multer.memoryStorage(),
  limits: { fileSize: 5 * 1024 * 1024 } // 5MB limit
});

app.post('/upload-config', upload.single('xmlFile'), (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    const xmlContent = req.file.buffer.toString('utf-8');

    // SECURE: Parse XML with all dangerous features disabled
    const xmlDoc = libxmljs.parseXml(xmlContent, {
      noent: false,        // Disable entity substitution
      nonet: true,         // Disable network access
      nocdata: false,      // Keep CDATA sections
      dtdload: false,      // Disable DTD loading
      dtdattr: false,      // Disable default DTD attributes
      dtdvalid: false,     // Disable DTD validation
      huge: false,         // Disable support for huge documents
      noblanks: false      // Keep blank nodes
    });

    // Extract configuration settings into JavaScript object
    const config = extractConfiguration(xmlDoc);

    res.json({
      success: true,
      configuration: config
    });

  } catch (error) {
    console.error('XML parsing error:', error.message);
    res.status(400).json({ 
      error: 'Invalid XML format',
      message: error.message 
    });
  }
});

function extractConfiguration(xmlDoc) {
  const config = {};

  // Extract root element
  const root = xmlDoc.root();
  
  if (!root) {
    throw new Error('No root element found');
  }

  // Extract configuration settings
  config.name = getElementText(root, 'name');
  config.version = getElementText(root, 'version');
  
  // Extract settings section
  const settingsNode = root.get('//settings');
  if (settingsNode) {
    config.settings = {};
    settingsNode.childNodes().forEach(node => {
      if (node.type() === 'element') {
        config.settings[node.name()] = node.text();
      }
    });
  }

  // Extract endpoints
  const endpointsNodes = root.find('//endpoints/endpoint');
  if (endpointsNodes && endpointsNodes.length > 0) {
    config.endpoints = endpointsNodes.map(endpoint => ({
      name: endpoint.attr('name')?.value(),
      url: endpoint.get('url')?.text(),
      method: endpoint.get('method')?.text(),
      timeout: endpoint.get('timeout')?.text()
    }));
  }

  // Extract authentication
  const authNode = root.get('//authentication');
  if (authNode) {
    config.authentication = {
      type: authNode.attr('type')?.value(),
      credentials: {}
    };
    authNode.childNodes().forEach(node => {
      if (node.type() === 'element') {
        config.authentication.credentials[node.name()] = node.text();
      }
    });
  }

  return config;
}

function getElementText(parent, elementName) {
  const element = parent.get(`//${elementName}`);
  return element ? element.text() : null;
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});